import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { login } from '../api';

// Replaces: templates/index.html + login logic from static/app.js

export default function Login() {
  const { login: setUser } = useAuth();
  const navigate = useNavigate();
  const [form, setForm]       = useState({ username_or_email: '', password: '' });
  const [error, setError]     = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const data = await login(form);
      setUser(data);
      navigate(`/${data.role}`);
    } catch (err) {
      setError(err.response?.data?.detail || 'Invalid credentials');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={s.page}>
      <div style={s.card}>
        <h1 style={s.logo}>💊 CareLine</h1>
        <p style={s.subtitle}>E-Clinic Management System</p>

        <form onSubmit={handleSubmit} style={s.form}>
          <label style={s.label}>Username or Email</label>
          <input style={s.input} type="text" placeholder="Enter username or email"
            value={form.username_or_email}
            onChange={e => setForm(f => ({ ...f, username_or_email: e.target.value }))} required />

          <label style={s.label}>Password</label>
          <input style={s.input} type="password" placeholder="Enter password"
            value={form.password}
            onChange={e => setForm(f => ({ ...f, password: e.target.value }))} required />

          {error && <p style={s.error}>{error}</p>}
          <button style={s.btn} type="submit" disabled={loading}>
            {loading ? 'Signing in…' : 'Sign In'}
          </button>
        </form>

        <div style={s.hint}>
          <small>
            <strong>Test credentials</strong><br />
            Superadmin: <code>muhammad.yasir / super123</code><br />
            Admin: <code>sarim.khan / admin123</code><br />
            Doctor: <code>ahmed.ali / doc123</code><br />
            Receptionist: <code>kamran.akmal / recep123</code>
          </small>
        </div>
      </div>
    </div>
  );
}

const s = {
  page: { minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center',
    background:'linear-gradient(135deg,#1a73e8,#0d47a1)', fontFamily:'Segoe UI,sans-serif' },
  card: { background:'white', borderRadius:16, padding:'40px 36px', width:'100%', maxWidth:420,
    boxShadow:'0 8px 32px rgba(0,0,0,.18)' },
  logo: { margin:0, fontSize:'1.8rem', color:'#1a73e8', textAlign:'center' },
  subtitle: { textAlign:'center', color:'#666', marginTop:4, marginBottom:28 },
  form: { display:'flex', flexDirection:'column', gap:4 },
  label: { fontSize:'.85rem', fontWeight:600, color:'#333', marginBottom:2, marginTop:12 },
  input: { padding:'10px 14px', borderRadius:8, border:'1px solid #ddd', fontSize:'.95rem' },
  btn: { marginTop:20, padding:12, borderRadius:8, border:'none', background:'#1a73e8',
    color:'white', fontSize:'1rem', fontWeight:600, cursor:'pointer' },
  error: { color:'#d32f2f', fontSize:'.85rem', margin:'8px 0 0' },
  hint: { marginTop:24, padding:12, background:'#f5f5f5', borderRadius:8,
    textAlign:'center', lineHeight:1.8, color:'#555' },
};
